class _Legend:
    """Stand-in for ``matplotlib.legend.Legend`` — returned by
    ``ax.legend()`` / ``plt.legend()``. Common user code:
        leg = ax.legend()
        leg.set_title('...'); leg.get_texts(); leg.set_loc(...)
    Plotly renders the legend from trace names automatically, so most
    of these are no-ops; we just expose the contract."""
    __getattr__ = _shim_getattr_fallback
    def __init__(self, handles=None, labels=None, loc=None, **kw):
        self._handles = list(handles) if handles else []
        self._labels = list(labels) if labels else []
        self._title = kw.get('title', '')
        self._loc = loc
        self._frameon = kw.get('frameon', True)
        self._visible = True
        self._draggable = False
    def get_title(self):
        class _T:
            def __init__(s, txt): s._txt = txt
            def get_text(s):    return s._txt
            def set_text(s, t): s._txt = str(t)
        return _T(self._title)
    def set_title(self, t, **kw):  self._title = str(t)
    def get_texts(self):
        class _LegTxt:
            def __init__(s, t): s._t = t
            def get_text(s):    return s._t
            def set_text(s, x): s._t = str(x)
        return [_LegTxt(l) for l in self._labels]
    def get_lines(self):           return list(self._handles)
    def get_patches(self):         return []
    def set_visible(self, v):      self._visible = bool(v)
    def get_visible(self):         return self._visible
    def draggable(self, *a, **kw): self._draggable = True
    def set_draggable(self, *a, **kw): self._draggable = True
    def remove(self):              pass


class _Spine:
    """Stand-in for ``matplotlib.spines.Spine`` — held in ``ax.spines``.
    User code commonly does ``ax.spines['top'].set_visible(False)``."""
    __getattr__ = _shim_getattr_fallback
    def __init__(self, name):
        self._name = name
        self._visible = True
        self._color = 'black'
        self._linewidth = 1.0
        self._linestyle = '-'
        self._position = ('outward', 0)
        self._bounds = None
    def set_visible(self, v):      self._visible = bool(v)
    def get_visible(self):         return self._visible
    def set_color(self, c):        self._color = c
    def get_edgecolor(self):       return self._color
    def set_edgecolor(self, c):    self._color = c
    def set_linewidth(self, w):    self._linewidth = float(w)
    def get_linewidth(self):       return self._linewidth
    def set_linestyle(self, s):    self._linestyle = s
    def set_position(self, p):     self._position = p
    def get_position(self):        return self._position
    def set_bounds(self, *a):      self._bounds = a
    def get_bounds(self):          return self._bounds


class _Spines(dict):
    """``ax.spines`` — dict of 4 (or more) named spines. Accessed both
    as a dict (``ax.spines['top']``) and as attrs (``ax.spines.top``)."""
    __getattr__ = _shim_getattr_fallback
    def __init__(self):
        super().__init__()
        for name in ('top', 'bottom', 'left', 'right'):
            self[name] = _Spine(name)
    # Lookup as attribute too (matplotlib added this in 3.4+).
    def __getattribute__(self, name):
        try:
            return dict.__getattribute__(self, name)
        except AttributeError:
            if name in self:
                return self[name]
            return _shim_getattr_fallback(self, name)
    def values(self):
        return list(dict.values(self))
    def items(self):
        return list(dict.items(self))


class _Annotation:
    """Stand-in for ``matplotlib.text.Annotation`` — returned by
    ``ax.annotate()``. User code may call ``set_text()``,
    ``set_position()``, ``arrow_patch.set_color()``, etc."""
