    def get_xbound(self):
        lim = self.get_xlim()
        if not lim or len(lim) != 2: return (0.0, 1.0)
        lo, hi = lim; return (min(lo, hi), max(lo, hi))
    def set_xbound(self, lower=None, upper=None):
        if hasattr(lower, '__len__') and upper is None: lower, upper = lower
        self.set_xlim(lower, upper)
    def get_ybound(self):
        lim = self.get_ylim()
        if not lim or len(lim) != 2: return (0.0, 1.0)
        lo, hi = lim; return (min(lo, hi), max(lo, hi))
    def set_ybound(self, lower=None, upper=None):
        if hasattr(lower, '__len__') and upper is None: lower, upper = lower
        self.set_ylim(lower, upper)
    def get_xmargin(self):                     return getattr(self, '_xm', 0.05)
    def get_ymargin(self):                     return getattr(self, '_ym', 0.05)
    def set_prop_cycle(self, *a, **kw):        self._prop_cycle = (a, kw)

    # Layout / transforms — return defaults.
    def apply_aspect(self, position=None):     pass
    def in_axes(self, mouseevent):             return True
    def contains_point(self, point):           return True
    def label_outer(self, remove_inner_ticks=False): pass
    def has_data(self):
        # True iff any child collection has at least one element.
        return bool(self.lines or self.collections or self.patches
                    or self.images or self.containers)
    def reset_position(self):                  pass

    def update_datalim(self, xys, updatex=True, updatey=True):
        """Expand this axes' data bounds to enclose ``xys`` (an Nx2
        array). Mirrors upstream's data-bounds accumulator used during
        autoscaling."""
        import numpy as _np
        if xys is None: return
        arr = _np.asarray(xys, dtype=float)
        if arr.size == 0: return
        if arr.ndim == 1:
            # Treat as single (x, y) pair.
            if arr.size < 2: return
            arr = arr.reshape(1, -1)[:, :2]
        bb = getattr(self, '_datalim', None)
        x0, y0 = float(arr[:, 0].min()), float(arr[:, 1].min())
        x1, y1 = float(arr[:, 0].max()), float(arr[:, 1].max())
        if bb is None:
            new_bb = [x0, y0, x1, y1]
        else:
            new_bb = list(bb)
            if updatex:
                new_bb[0] = min(new_bb[0], x0); new_bb[2] = max(new_bb[2], x1)
            if updatey:
                new_bb[1] = min(new_bb[1], y0); new_bb[3] = max(new_bb[3], y1)
        self._datalim = tuple(new_bb)

    def use_sticky_edges(self):                return True

    def get_data_ratio(self):
        try:
            xl = self.get_xlim(); yl = self.get_ylim()
            if not xl or not yl: return 1.0
            x0, x1 = xl; y0, y1 = yl
            return abs((y1 - y0) / (x1 - x0)) if (x1 - x0) else 1.0
        except Exception:
            return 1.0

    def get_default_bbox_extra_artists(self):  return []
    def get_tightbbox(self, renderer=None, *, call_axes_locator=True,
                      bbox_extra_artists=None): return None
    def get_gridspec(self):                    return getattr(self, '_subplotspec', None)
    def get_legend_handles_labels(self, *a, **kw):
        """Discover labeled artists across lines/patches/collections/
        containers. Mirrors matplotlib's auto-discovery so callers that
        do ``h, l = ax.get_legend_handles_labels(); ax.legend(h, l)``
        actually get back the artists they've plotted. Labels prefixed
        with ``_`` are skipped (matplotlib convention for hidden)."""
        handles, labels = [], []
        for src in (getattr(self, 'lines', []), getattr(self, 'patches', []),
                    getattr(self, 'collections', []),
                    getattr(self, 'containers', [])):
            for artist in src:
                lbl = None
                getter = getattr(artist, 'get_label', None)
                if callable(getter):
                    try: lbl = getter()
                    except Exception: lbl = None
                if lbl and not str(lbl).startswith('_'):
                    handles.append(artist)
                    labels.append(str(lbl))
        return handles, labels
    def get_next_color(self):
        try: return _next_color()
        except Exception: return None

    def get_shared_x_axes(self):
        class _G:
            def __init__(s, ax): s._members = [ax]
            def get_siblings(s, a): return list(s._members)
            def joined(s, a, b): return a is b
            def __iter__(s): return iter([s._members])
        return _G(self)
    def get_shared_y_axes(self):  return self.get_shared_x_axes()
    def sharex(self, other):      self._sharex = other
    def sharey(self, other):      self._sharey = other

    # Coordinate transforms — return identity stand-ins.
    class _IdXform:
        def transform(self, pts): return pts
        def inverted(self): return self
    def get_xaxis_transform(self, which='grid'):  return self._IdXform()
    def get_yaxis_transform(self, which='grid'):  return self._IdXform()
    def get_xaxis_text1_transform(self, pad):
        return self._IdXform(), 'top', 'center'
    def get_xaxis_text2_transform(self, pad):
        return self._IdXform(), 'bottom', 'center'
    def get_yaxis_text1_transform(self, pad):
        return self._IdXform(), 'center', 'right'
    def get_yaxis_text2_transform(self, pad):
        return self._IdXform(), 'center', 'left'

    # Container/child management — backed by per-instance lists.
    def _ensure_collections(self):
        # All of these are initialized as instance lists in
        # ``_Axes.__init__`` now. This helper remains for backwards
        # compatibility with any caller that polls a non-init'd Axes
        # — it only fills in missing attributes, never overwrites.
        for attr in ('lines', 'patches', 'collections', 'images', 'texts',
                     'artists', 'tables', 'containers'):
            if not hasattr(self, attr):
                setattr(self, attr, [])

    # ``lines`` / ``patches`` / ``collections`` / ``images`` / ``texts`` /
    # ``artists`` / ``tables`` are real INSTANCE lists, populated by
    # ``_Axes.plot()`` / ``scatter()`` / ``bar()`` etc. so legend
    # auto-discovery and Axes introspection (``ax.lines``,
    # ``ax.get_children()``) work. Do NOT redeclare them as
    # ``@property`` — that would silently block the assignments in
    # ``__init__`` with ``property has no setter`` (same trap as the
    # earlier xaxis/yaxis/spines bugs).

    def get_lines(self):       self._ensure_collections(); return list(self.lines)
    def get_images(self):      self._ensure_collections(); return list(self.images)
    def add_child_axes(self, ax):       return ax

    def add_container(self, c):
        self._ensure_collections(); self.containers.append(c); return c

    def add_image(self, im):
        self._ensure_collections(); self.images.append(im); return im

    def add_table(self, t):
        self._ensure_collections(); self.tables.append(t); return t

    def add_artist(self, artist):
        """Add a free-form artist to this axes' children."""
        self._ensure_collections(); self.artists.append(artist)
        try: artist.axes = self
        except Exception: pass
        return artist

    def add_line(self, line):
        self._ensure_collections(); self.lines.append(line)
        try: line.axes = self
        except Exception: pass
        return line

    def add_patch(self, patch):
        self._ensure_collections(); self.patches.append(patch)
        try: patch.axes = self
        except Exception: pass
        return patch

    def add_collection(self, coll, autolim=True):
        self._ensure_collections(); self.collections.append(coll)
        try: coll.axes = self
        except Exception: pass
        if autolim:
            try:
                offsets = coll.get_offsets()
                if offsets is not None: self.update_datalim(offsets)
            except Exception: pass
        return coll

