    # 3D view / projection / aspect helpers
    def view_init(self, elev=None, azim=None, roll=None, vertical_axis='z', share=False):
        """Set the elevation/azimuth viewing angle. Maps matplotlib's
        (elev, azim) in degrees onto plotly's ``scene.camera.eye`` unit
        vector (radius ~1.25 by default)."""
        import math as _m
        e_rad = _m.radians(float(elev) if elev is not None else 30.0)
        a_rad = _m.radians(float(azim) if azim is not None else -60.0)
        r = 1.75
        eye_x = r * _m.cos(e_rad) * _m.cos(a_rad)
        eye_y = r * _m.cos(e_rad) * _m.sin(a_rad)
        eye_z = r * _m.sin(e_rad)
        cam = _layout_updates.setdefault('scene', {}).setdefault('camera', {})
        cam['eye'] = dict(x=eye_x, y=eye_y, z=eye_z)
    def set_proj_type(self, proj_type, **kw):
        if proj_type == 'ortho':
            _layout_updates.setdefault('scene', {}).setdefault('camera', {})['projection'] = dict(type='orthographic')
        elif proj_type == 'persp':
            _layout_updates.setdefault('scene', {}).setdefault('camera', {})['projection'] = dict(type='perspective')
    def set_box_aspect(self, aspect, **kw):
        if _has_len(aspect) and len(aspect) == 3:
            ax_, ay, az = (float(v) for v in aspect)
            _layout_updates.setdefault('scene', {})['aspectmode'] = 'manual'
            _layout_updates['scene']['aspectratio'] = dict(x=ax_, y=ay, z=az)
    def set_top_view(self, *a, **kw):    pass
    def get_proj(self):                  return None
    def get_w_lims(self):                return (0.0, 1.0, 0.0, 1.0, 0.0, 1.0)
    def auto_scale_xyz(self, X=None, Y=None, Z=None, had_data=None):
        """Compute 3D axis ranges from the provided X/Y/Z arrays and
        push them to plotly's scene.{x,y,z}axis.range."""
        import numpy as _np
        for arr, ax_name in ((X, 'xaxis'), (Y, 'yaxis'), (Z, 'zaxis')):
            if arr is None:
                continue
            a = _np.asarray(arr, dtype=float).ravel()
            a = a[_np.isfinite(a)]
            if a.size == 0: continue
            scene = _layout_updates.setdefault('scene', {})
            scene.setdefault(ax_name, {})['range'] = [float(a.min()), float(a.max())]

    def autoscale(self, enable=True, axis='both', tight=None):
        """Toggle auto-ranging on the x/y/z axes."""
        for ax_short in ('x', 'y') if axis != 'z' else ():
            d = _layout_updates.setdefault(self._axis_id(ax_short), {})
            d['autorange'] = bool(enable)
        if self._is_3d and axis in ('z', 'both'):
            scene = _layout_updates.setdefault('scene', {})
            scene.setdefault('zaxis', {})['autorange'] = bool(enable)

    def autoscale_view(self, *a, **kw):
        # Tight/scaling alias — call autoscale to push autorange back on.
        return self.autoscale(enable=True, axis='both')
