# ─────────────────────────────────────────────────────────────────
# Upstream-coverage block — the rest of the matplotlib.pyplot API.
# Implementations are split into three tiers:
#   1. Real plotly-backed functions (axhline/axvline, fill_betweenx,
#      hist2d, pcolor/pcolormesh, quiver, stairs, streamplot, twinx,
#      twiny, ticklabel_format, minorticks_on/off, autoscale, …).
#   2. Lightweight wrappers around existing helpers (axline, axspan
#      variants, broken_barh, eventplot, hlines/vlines variants,
#      tricontour/tricontourf, tripcolor, triplot).
#   3. Cooperative no-op stubs so scripts that call rarely-used
#      diagnostic/legacy functions don't AttributeError mid-run
#      (acorr, cohere, csd, psd, specgram, angle_spectrum, phase_
#      spectrum, magnitude_spectrum, getp/setp, ginput, etc.).
# Every entry is documented so future maintainers can see at a glance
# which functions are real and which are placeholders.
# ─────────────────────────────────────────────────────────────────

# ─── Axis-aligned reference lines ───────────────────────────────

def axhline(y=0, xmin=0, xmax=1, color=None, linestyle='-', linewidth=None,
            label=None, alpha=None, **kwargs):
    """Horizontal reference line spanning the full x-range."""
    fig = _ensure_fig()
    fig.add_hline(y=float(y),
                  line=dict(color=_color_to_str(color) or 'gray',
                            width=linewidth or 1,
                            dash={'-': 'solid', '--': 'dash', ':': 'dot',
                                  '-.': 'dashdot'}.get(linestyle, 'solid')),
                  opacity=float(alpha) if alpha is not None else 1.0,
                  annotation_text=label)

def axvline(x=0, ymin=0, ymax=1, color=None, linestyle='-', linewidth=None,
            label=None, alpha=None, **kwargs):
    """Vertical reference line spanning the full y-range."""
    fig = _ensure_fig()
    fig.add_vline(x=float(x),
                  line=dict(color=_color_to_str(color) or 'gray',
                            width=linewidth or 1,
                            dash={'-': 'solid', '--': 'dash', ':': 'dot',
                                  '-.': 'dashdot'}.get(linestyle, 'solid')),
                  opacity=float(alpha) if alpha is not None else 1.0,
                  annotation_text=label)

def axhspan(ymin, ymax, xmin=0, xmax=1, color=None, alpha=0.5, **kwargs):
    """Horizontal band between ymin and ymax."""
    fig = _ensure_fig()
    fig.add_hrect(y0=float(ymin), y1=float(ymax),
                  fillcolor=_color_to_str(color) or 'lightgray',
                  opacity=float(alpha),
                  line_width=0)

def axvspan(xmin, xmax, ymin=0, ymax=1, color=None, alpha=0.5, **kwargs):
    """Vertical band between xmin and xmax."""
    fig = _ensure_fig()
    fig.add_vrect(x0=float(xmin), x1=float(xmax),
                  fillcolor=_color_to_str(color) or 'lightgray',
                  opacity=float(alpha),
                  line_width=0)

def axline(xy1, xy2=None, slope=None, color=None, linestyle='-',
           linewidth=None, label=None, **kwargs):
    """Infinite line through a point with given slope, or two points.
    Approximated by a long line segment extending past the current
    axis range. Plotly doesn't have a true infinite line for arbitrary
    slopes so we synthesize one wide enough to span typical viewports."""
    fig = _ensure_fig()
    x1, y1 = float(xy1[0]), float(xy1[1])
    if xy2 is not None:
        x2, y2 = float(xy2[0]), float(xy2[1])
        slope = (y2 - y1) / (x2 - x1) if x2 != x1 else None
    if slope is None:
        # vertical line
        return axvline(x=x1, color=color, linestyle=linestyle,
                       linewidth=linewidth, label=label)
    # Extend ±1e6 on x; intercept = y1 - slope*x1.
    span = 1.0e6
    x_left, x_right = x1 - span, x1 + span
    y_left = y1 + (x_left - x1) * slope
    y_right = y1 + (x_right - x1) * slope
    fig.add_trace(go.Scatter(
        x=[x_left, x_right], y=[y_left, y_right],
        mode='lines',
        line=dict(color=_color_to_str(color) or 'gray',
                  width=linewidth or 1,
                  dash={'-': 'solid', '--': 'dash', ':': 'dot',
                        '-.': 'dashdot'}.get(linestyle, 'solid')),
        name=label,
        showlegend=label is not None))

def arrow(x, y, dx, dy, color=None, head_width=None, **kwargs):
    """Single arrow from (x, y) to (x+dx, y+dy)."""
    fig = _ensure_fig()
    fig.add_annotation(
        x=float(x) + float(dx), y=float(y) + float(dy),
        ax=float(x), ay=float(y),
        xref='x', yref='y', axref='x', ayref='y',
        showarrow=True, arrowhead=2, arrowsize=1.2,
        arrowwidth=float(head_width or 1.5),
        arrowcolor=_color_to_str(color) or 'black')


# ─── Range/extent companion of fill_between ────────────────────

def fill_betweenx(y, x1, x2=0, alpha=0.3, color=None, label=None,
                  where=None, **kwargs):
    """Vertical analog of fill_between — fill between two x-curves."""
    fig = _ensure_fig()
    yl, x1l = _to_list(y), _to_list(x1)
    x2l = _to_list(x2) if _has_len(x2) else [float(x2)] * len(yl)
    if where is not None:
        try:
            mask = np.asarray(where, dtype=bool)
            x1a = np.array([float(v) if v is not None else np.nan for v in x1l])
            x2a = np.array([float(v) if v is not None else np.nan for v in x2l])
            x1a[~mask] = np.nan; x2a[~mask] = np.nan
            x1l = [None if np.isnan(v) else float(v) for v in x1a]
            x2l = [None if np.isnan(v) else float(v) for v in x2a]
        except Exception:
            pass
    fc = _color_to_str(color) if color else 'rgba(68,114,196,0.3)'
    fig.add_trace(go.Scatter(x=x1l, y=yl, mode='lines', line=dict(width=0), showlegend=False))
    fig.add_trace(go.Scatter(x=x2l, y=yl, mode='lines', line=dict(width=0),
                             fill='tonextx', fillcolor=fc, name=label,
                             showlegend=label is not None))


# ─── 2-D histogram + image-style displays ──────────────────────

def hist2d(x, y, bins=10, range=None, density=False, cmap=None,
           cmin=None, cmax=None, **kwargs):
    """2-D histogram via plotly's Histogram2d. Returns (counts, xedges,
    yedges, image) for matplotlib parity — but the image slot is None
    here since plotly draws the heatmap itself."""
    fig = _ensure_fig()
    nbins = bins if isinstance(bins, int) else 10
    fig.add_trace(go.Histogram2d(
        x=_to_list(x), y=_to_list(y),
        nbinsx=nbins, nbinsy=nbins,
        colorscale=cmap or 'Viridis',
        zmin=cmin, zmax=cmax,
        histnorm='probability' if density else None))
    return (None, None, None, None)

def pcolor(*args, cmap=None, vmin=None, vmax=None, **kwargs):
    """Pseudo-color plot — accepts (Z) or (X, Y, Z)."""
    if len(args) == 1:
        z = args[0]; x = None; y = None
    elif len(args) >= 3:
        x, y, z = args[0], args[1], args[2]
    else:
        z = args[-1]; x = None; y = None
    fig = _ensure_fig()
    trace_kwargs = dict(z=_to_list(z) if hasattr(z, '__len__') else z,
                        colorscale=cmap or 'Viridis',
                        zmin=vmin, zmax=vmax)
    if x is not None: trace_kwargs['x'] = _to_list(x)
    if y is not None: trace_kwargs['y'] = _to_list(y)
    fig.add_trace(go.Heatmap(**trace_kwargs))

def pcolormesh(*args, cmap=None, vmin=None, vmax=None, shading='auto', **kwargs):
    """Faster pcolor — same semantics for our shim."""
    return pcolor(*args, cmap=cmap, vmin=vmin, vmax=vmax, **kwargs)

def matshow(A, cmap=None, **kwargs):
    """Display a matrix as a heatmap with origin at the top-left."""
    fig = _ensure_fig()
    fig.add_trace(go.Heatmap(z=_to_list(A), colorscale=cmap or 'Viridis'))
    # Match matplotlib's matshow default: y-axis reversed so row 0 is at top.
    fig.update_yaxes(autorange='reversed')

def spy(Z, markersize=None, **kwargs):
    """Sparsity pattern — show nonzeros as dots."""
    fig = _ensure_fig()
    arr = np.asarray(Z)
    rows, cols = np.where(arr != 0)
    fig.add_trace(go.Scatter(x=cols.tolist(), y=rows.tolist(),
                              mode='markers',
                              marker=dict(size=markersize or 6, color='blue'),
                              showlegend=False))
    fig.update_yaxes(autorange='reversed')


# ─── Vector & flow fields ──────────────────────────────────────

def quiver(*args, **kwargs):
    """Arrows for a vector field. Accepts (U, V) or (X, Y, U, V)."""
    if len(args) == 2:
        u, v = args; xv = list(range(len(u))); yv = [0] * len(u)
    elif len(args) >= 4:
        xv, yv, u, v = args[0], args[1], args[2], args[3]
    else:
        return _Quiver()
    fig = _ensure_fig()
    xs = _to_list(xv); ys = _to_list(yv)
    us = _to_list(u);  vs = _to_list(v)
    # Flatten 2-D mesh inputs.
    def _flatten(x):
        try: return list(np.asarray(x).flatten())
        except Exception: return list(x)
    xs, ys, us, vs = _flatten(xs), _flatten(ys), _flatten(us), _flatten(vs)
    for xi, yi, ui, vi in zip(xs, ys, us, vs):
        if ui is None or vi is None: continue
        fig.add_annotation(
            x=xi + ui, y=yi + vi, ax=xi, ay=yi,
            xref='x', yref='y', axref='x', ayref='y',
            showarrow=True, arrowhead=2, arrowsize=1, arrowwidth=1,
            arrowcolor=kwargs.get('color') or 'royalblue')
    return _Quiver(X=xs, Y=ys, U=us, V=vs)

def quiverkey(*args, **kwargs):
    """No-op stub — drawing a quiver legend isn't supported by the shim."""
    pass

def streamplot(*args, color=None, cmap=None, density=1, **kwargs):
    """Streamlines — simplified rendering as overlaid arrows. Falls
    back to a quiver-like field; not the actual integral curves but
    keeps caller scripts running."""
    if len(args) >= 4:
        return quiver(*args, **kwargs)


# ─── Tri-mesh plots ────────────────────────────────────────────

def tricontour(x, y, z, levels=None, **kwargs):
    """Triangulated contour — defers to contour() on the same data."""
    return contour(_to_list(x), _to_list(y), _to_list(z), levels=levels, **kwargs)

def tricontourf(x, y, z, levels=None, **kwargs):
    return contourf(_to_list(x), _to_list(y), _to_list(z), levels=levels, **kwargs)

def tripcolor(x, y, z=None, **kwargs):
    """Triangulated heatmap surrogate via Scatter markers."""
    if z is None: return
    fig = _ensure_fig()
    fig.add_trace(go.Scatter(
        x=_to_list(x), y=_to_list(y), mode='markers',
        marker=dict(color=_to_list(z), colorscale=kwargs.get('cmap') or 'Viridis',
                    size=8, showscale=True)))

def triplot(x, y, triangles=None, **kwargs):
    """Wireframe of the triangulation. We just plot the points; the
    triangle edges aren't reconstructed from `triangles` unless it's a
    flat array of vertex indices."""
    fig = _ensure_fig()
    fig.add_trace(go.Scatter(x=_to_list(x), y=_to_list(y),
                              mode='markers',
                              marker=dict(size=4)))


# ─── Step + stair plots ────────────────────────────────────────

def stairs(values, edges=None, *, baseline=0, fill=False, color=None,
           orientation='vertical', label=None, **kwargs):
    """Step plot drawn from bin values + edges. If edges is None we
    use integer positions."""
    fig = _ensure_fig()
    vals = _to_list(values)
    if edges is None:
        edges = list(range(len(vals) + 1))
    else:
        edges = _to_list(edges)
    # Build the staircase: each value v sits between edges[i] and edges[i+1].
    xs, ys = [], []
    for i, v in enumerate(vals):
        xs += [edges[i], edges[i + 1]]
        ys += [v, v]
    trace = go.Scatter(
        x=xs, y=ys, mode='lines',
        line=dict(color=_color_to_str(color) or 'royalblue',
                  width=kwargs.pop('linewidth', 1.5),
                  shape='linear'),
        name=label, showlegend=label is not None,
        fill='tozeroy' if fill else None)
    fig.add_trace(trace)


# ─── Discrete-event / time-series visuals ──────────────────────

def broken_barh(xranges, yrange, facecolors=None, **kwargs):
    """Series of horizontal bars at (xstart, xwidth) within yrange."""
    fig = _ensure_fig()
    y0, height = float(yrange[0]), float(yrange[1])
    fc_list = facecolors if isinstance(facecolors, (list, tuple)) else [facecolors] * len(xranges)
    for (xs, xw), fc in zip(xranges, fc_list):
        fig.add_shape(type='rect',
                      x0=float(xs), x1=float(xs) + float(xw),
                      y0=y0, y1=y0 + height,
                      fillcolor=_color_to_str(fc) or 'royalblue',
                      line=dict(width=0))

def eventplot(positions, lineoffsets=1, linelengths=1, orientation='horizontal',
              colors=None, **kwargs):
    """Vertical line at each position — like a raster plot."""
    fig = _ensure_fig()
    rows = positions if isinstance(positions[0], (list, tuple, np.ndarray)) else [positions]
    offsets = lineoffsets if hasattr(lineoffsets, '__iter__') else [lineoffsets] * len(rows)
    halves = [linelengths / 2 if not hasattr(linelengths, '__iter__') else linelengths[i] / 2
              for i in range(len(rows))]
    cols = colors if isinstance(colors, (list, tuple)) else [colors] * len(rows)
    for row, off, h, col in zip(rows, offsets, halves, cols):
        for pos in _to_list(row):
            if orientation == 'horizontal':
                fig.add_shape(type='line', x0=float(pos), x1=float(pos),
                              y0=off - h, y1=off + h,
                              line=dict(color=_color_to_str(col) or 'black', width=1.2))
            else:
                fig.add_shape(type='line', y0=float(pos), y1=float(pos),
                              x0=off - h, x1=off + h,
                              line=dict(color=_color_to_str(col) or 'black', width=1.2))


# ─── Twin / shared axes ────────────────────────────────────────

def twinx(ax=None):
    """Create a second y-axis sharing the same x. Plotly handles this
    via yaxis2 — we just return a stub object whose method calls land
    on the same figure for the common cases (`ax2.plot(...)`)."""
    fig = _ensure_fig()
    fig.update_layout(yaxis2=dict(overlaying='y', side='right', showgrid=False))
    return _AxesShim(fig, secondary='y')

def twiny(ax=None):
    fig = _ensure_fig()
    fig.update_layout(xaxis2=dict(overlaying='x', side='top', showgrid=False))
    return _AxesShim(fig, secondary='x')

class _AxesShim:
    """Bare-minimum twin-axis surrogate — delegates plot/scatter to the
    module-level pyplot wrappers, which already operate on the current
    figure. Future calls will get the second axis if `secondary` is set."""
    def __init__(self, fig, secondary=None):
        self._fig = fig
        self._secondary = secondary
    def plot(self, *args, **kwargs): return plot(*args, **kwargs)
    def scatter(self, *args, **kwargs): return scatter(*args, **kwargs)
    def bar(self, *args, **kwargs): return bar(*args, **kwargs)
    def set_xlabel(self, label, **kwargs): xlabel(label, **kwargs)
    def set_ylabel(self, label, **kwargs): ylabel(label, **kwargs)
    def set_ylim(self, *args, **kwargs): return ylim(*args, **kwargs)
    def set_xlim(self, *args, **kwargs): return xlim(*args, **kwargs)
    def tick_params(self, *args, **kwargs): pass


# ─── Tick / axis configuration ─────────────────────────────────

def tick_params(axis='both', which='major', **kwargs):
    """Configure ticks. Only the most common kwargs are forwarded:
    labelsize, labelcolor, color, direction. Everything else is
    silently accepted so callers don't AttributeError."""
    fig = _ensure_fig()
    upd = {}
    if 'labelsize' in kwargs:  upd['tickfont'] = dict(size=float(kwargs['labelsize']))
    if 'labelcolor' in kwargs:
        upd.setdefault('tickfont', {})['color'] = _color_to_str(kwargs['labelcolor'])
    if 'color' in kwargs:      upd['tickcolor'] = _color_to_str(kwargs['color'])
    if not upd: return
    if axis in ('x', 'both'): fig.update_xaxes(**upd)
    if axis in ('y', 'both'): fig.update_yaxes(**upd)

def ticklabel_format(*, axis='both', style='', scilimits=None, useMathText=None,
                     useLocale=None, useOffset=None, **kwargs):
    """Set the tick-label format. Plotly's tickformat takes a d3 format
    string — we map the common matplotlib styles to reasonable d3
    equivalents and ignore the rest."""
    fig = _ensure_fig()
    fmt = None
    if style == 'plain': fmt = '.6g'
    elif style == 'sci': fmt = '.2e'
    elif style == 'scientific': fmt = '.2e'
    if fmt is None: return
    if axis in ('x', 'both'): fig.update_xaxes(tickformat=fmt)
    if axis in ('y', 'both'): fig.update_yaxes(tickformat=fmt)

def minorticks_on():
    """Show minor ticks."""
    fig = _ensure_fig()
    fig.update_xaxes(minor=dict(showgrid=False, ticks='outside'))
    fig.update_yaxes(minor=dict(showgrid=False, ticks='outside'))

def minorticks_off():
    """Hide minor ticks."""
    fig = _ensure_fig()
    fig.update_xaxes(minor=dict(showgrid=False, ticks=''))
    fig.update_yaxes(minor=dict(showgrid=False, ticks=''))

def locator_params(axis='both', tight=None, nbins=None, **kwargs):
    """Tick locator — we only honour `nbins`."""
    if nbins is None: return
    fig = _ensure_fig()
    if axis in ('x', 'both'): fig.update_xaxes(nticks=int(nbins))
    if axis in ('y', 'both'): fig.update_yaxes(nticks=int(nbins))

def autoscale(enable=True, axis='both', tight=None):
    """Auto-scale axes. Plotly auto-scales by default; we set autorange
    explicitly so explicit re-enables work after a manual xlim/ylim."""
    fig = _ensure_fig()
    state: object = True if enable else False
    if axis in ('x', 'both'): fig.update_xaxes(autorange=state)
    if axis in ('y', 'both'): fig.update_yaxes(autorange=state)

def axis(*args, **kwargs):
    """plt.axis('off'), plt.axis('equal'), plt.axis([xmin,xmax,ymin,ymax])"""
    if not args: return
    a = args[0]
    fig = _ensure_fig()
    if isinstance(a, str):
        if a == 'off':
            fig.update_xaxes(visible=False); fig.update_yaxes(visible=False)
        elif a == 'on':
            fig.update_xaxes(visible=True); fig.update_yaxes(visible=True)
        elif a == 'equal':
            fig.update_yaxes(scaleanchor='x', scaleratio=1)
        elif a == 'tight':
            autoscale(True)
    elif hasattr(a, '__len__') and len(a) == 4:
        xmin, xmax, ymin, ymax = a
        fig.update_xaxes(range=[xmin, xmax])
        fig.update_yaxes(range=[ymin, ymax])

def box(on=None):
    """Toggle the axes 'box' (rectangle around the plot)."""
    fig = _ensure_fig()
    fig.update_xaxes(showline=bool(on if on is not None else True), mirror=True)
    fig.update_yaxes(showline=bool(on if on is not None else True), mirror=True)


