# ─── Spectral / signal-processing — delegate to mlab so callers
# actually get computed PSD/coherence/etc. arrays back instead of None.


def acorr(x, **kwargs):
    """Plot autocorrelation. Returns (lags, c, line, b) tuple."""
    from matplotlib.mlab import detrend_none
    import numpy as _np
    x = _np.asarray(x, dtype=float)
    detrend = kwargs.pop('detrend', detrend_none)
    x = detrend(x)
    maxlags = kwargs.pop('maxlags', 10)
    c = _np.correlate(x, x, mode='full') / (_np.dot(x, x) or 1.0)
    n = len(x)
    lags = _np.arange(-maxlags, maxlags + 1)
    c = c[n - 1 - maxlags: n + maxlags]
    return lags, c, None, None


def cohere(x, y, **kwargs):
    """Coherence between x and y — delegate to mlab.cohere."""
    from matplotlib.mlab import cohere as _coh
    NFFT = kwargs.get('NFFT', 256); Fs = kwargs.get('Fs', 2)
    return _coh(x, y, NFFT=NFFT, Fs=Fs)


def csd(x, y, **kwargs):
    """Cross spectral density — delegate to mlab.csd."""
    from matplotlib.mlab import csd as _csd
    return _csd(x, y, NFFT=kwargs.get('NFFT', 256), Fs=kwargs.get('Fs', 2))


def psd(x, **kwargs):
    """Power spectral density — delegate to mlab.psd."""
    from matplotlib.mlab import psd as _psd
    return _psd(x, NFFT=kwargs.get('NFFT', 256), Fs=kwargs.get('Fs', 2))


def specgram(x, **kwargs):
    """Spectrogram — delegate to mlab.specgram."""
    from matplotlib.mlab import specgram as _sg
    return _sg(x, NFFT=kwargs.get('NFFT', 256), Fs=kwargs.get('Fs', 2))


def magnitude_spectrum(x, **kwargs):
    """Magnitude spectrum — delegate to mlab.magnitude_spectrum."""
    from matplotlib.mlab import magnitude_spectrum as _ms
    return _ms(x, Fs=kwargs.get('Fs', 2))


def phase_spectrum(x, **kwargs):
    """Phase spectrum — delegate to mlab.phase_spectrum."""
    from matplotlib.mlab import phase_spectrum as _ps
    return _ps(x, Fs=kwargs.get('Fs', 2))


def angle_spectrum(x, **kwargs):
    """Angle spectrum — delegate to mlab.angle_spectrum."""
    from matplotlib.mlab import angle_spectrum as _as
    return _as(x, Fs=kwargs.get('Fs', 2))


def xcorr(x, y, **kwargs):
    """Cross-correlation between x and y. Returns (lags, c, line, b)."""
    import numpy as _np
    x = _np.asarray(x, dtype=float)
    y = _np.asarray(y, dtype=float)
    maxlags = kwargs.pop('maxlags', 10)
    n = max(len(x), len(y))
    c = _np.correlate(x, y, mode='full')
    norm = kwargs.pop('normed', True)
    if norm:
        c = c / (_np.sqrt(_np.dot(x, x) * _np.dot(y, y)) or 1.0)
    lags = _np.arange(-maxlags, maxlags + 1)
    c = c[n - 1 - maxlags: n + maxlags]
    return lags, c, None, None


