def subplots_adjust(left=None, bottom=None, right=None, top=None,
                    wspace=None, hspace=None):
    """Adjust subplot margins. Mapped to plotly layout margins/gap."""
    fig = _ensure_fig()
    upd = {}
    margin = {}
    if left is not None:   margin['l'] = int((left or 0) * 60)
    if right is not None:  margin['r'] = int((1 - right) * 60)
    if top is not None:    margin['t'] = int((1 - top) * 60)
    if bottom is not None: margin['b'] = int((bottom or 0) * 60)
    if margin: upd['margin'] = margin
    if upd: fig.update_layout(**upd)

def subplot2grid(shape, loc, rowspan=1, colspan=1, **kwargs):
    """Approximate by returning a fresh Axes — geometry isn't honoured."""
    return _ensure_fig()

def subplot_mosaic(mosaic, **kwargs):
    """Return a (fig, dict-of-axes) tuple keyed by label, like upstream."""
    fig = _ensure_fig()
    labels: list = []
    if isinstance(mosaic, str):
        for row in mosaic.splitlines():
            for ch in row.split():
                if ch and ch != '.' and ch not in labels: labels.append(ch)
    elif isinstance(mosaic, (list, tuple)):
        for row in mosaic:
            for ch in row:
                if ch and ch != '.' and ch not in labels: labels.append(ch)
    axes_map = {lbl: _AxesShim(fig) for lbl in labels}
    return fig, axes_map

