def get(obj, *args, **kwargs):
    """Inspect properties on a Plotly object. Matches upstream's
    flexible signature: ``get(obj)`` returns the object; ``get(obj,
    name)`` returns the value of that property."""
    if not args and not kwargs:
        return obj
    name = args[0] if args else kwargs.get('property')
    return getattr(obj, name, None)

def getp(obj, *args, **kwargs):
    """Alias of :func:`get`."""
    return get(obj, *args, **kwargs)

def setp(obj, *args, **kwargs):
    """Set properties — best-effort attribute assignment."""
    for k, v in kwargs.items():
        try: setattr(obj, k, v)
        except Exception: pass


# ─── Image read/write ──────────────────────────────────────────

def imread(fname, format=None):
    """Read an image into a numpy array."""
    try:
        from PIL import Image
        return np.asarray(Image.open(fname))
    except Exception:
        return np.zeros((1, 1, 4), dtype=np.uint8)

def imsave(fname, arr, **kwargs):
    """Save a numpy array as an image."""
    try:
        from PIL import Image
        a = np.asarray(arr)
        if a.dtype != np.uint8:
            mn, mx = float(a.min()), float(a.max())
            a = ((a - mn) / (mx - mn + 1e-12) * 255).astype(np.uint8)
        Image.fromarray(a).save(fname)
    except Exception as e:
        print(f"[mpl→plotly] imsave error: {e}", file=_sys.__stderr__)


