def grouped_bar(*args, **kwargs):
    """3.10+ alias — defer to bar(); group placement is plotly-managed."""
    return bar(*args, **kwargs)

def ecdf(x, **kwargs):
    """Empirical CDF — sort + step plot."""
    arr = np.sort(np.asarray(_to_list(x)))
    n = len(arr)
    if n == 0: return
    ys = np.arange(1, n + 1) / n
    step(arr.tolist(), ys.tolist(), where='post', **kwargs)


