# matplotlib exposes one function per cmap that switches the default
# (`viridis()` → set_cmap('viridis')). Generated for every standard map.

def _make_cmap_setter(name):
    def setter():
        set_cmap(name)
    setter.__name__ = name
    setter.__doc__ = f"Set the current colormap to '{name}'."
    return setter

for _cmap in ('viridis', 'inferno', 'plasma', 'magma', 'cividis',
              'jet', 'hot', 'cool', 'gray', 'bone', 'pink',
              'spring', 'summer', 'autumn', 'winter',
              'hsv', 'flag', 'prism', 'copper', 'nipy_spectral'):
    globals()[_cmap] = _make_cmap_setter(_cmap)


