def figaspect(arg):
    """Return (width, height) tuple for a figure with the given aspect.

    ``arg`` is either a number (the aspect ratio) or a 2-D array
    whose shape is used to compute the aspect.
    """
    try:
        ar = float(arg)
    except (TypeError, ValueError):
        try:
            ar = float(arg.shape[0]) / float(arg.shape[1])
        except Exception:
            ar = 1.0
    w = 8.0
    return (w, w * ar)


