def secondary_xaxis(location='top', *, functions=None, **kwargs):
    """Module-level convenience that delegates to ``gca().secondary_xaxis``.
    Real matplotlib only exposes this on Axes; the pyplot stub mirrors
    that signature so scripts that call it standalone don't crash."""
    ax = gca()
    if hasattr(ax, 'secondary_xaxis'):
        return ax.secondary_xaxis(location, functions=functions, **kwargs)
    # Last-resort: just return the same axes.
    return ax


def secondary_yaxis(location='right', *, functions=None, **kwargs):
    """Module-level convenience that delegates to ``gca().secondary_yaxis``."""
    ax = gca()
    if hasattr(ax, 'secondary_yaxis'):
        return ax.secondary_yaxis(location, functions=functions, **kwargs)
    return ax


# ──────────────────────────────────────────────────────────────
# Module-level __getattr__ catch-all.
#
# Anything the user calls as ``plt.foo(...)`` that we haven't
# explicitly shimmed lands here. Returns a no-op callable that
# logs the missing name once so the gap is visible but the script
# keeps running. This is the last safety net on top of all the
# class-level fallbacks (_Axes.__getattr__, _SafeFigure.__getattr__,
# _PathCollection.__getattr__, etc.) — together they guarantee
# that no matplotlib API call raises AttributeError on this shim.
# ──────────────────────────────────────────────────────────────

_pyplot_missing_warned = set()


def __getattr__(name):
    """PEP 562 module __getattr__ — invoked when normal module
    attribute lookup fails. Returns a no-op + logs once. Lets
    scripts call any matplotlib.pyplot function without crashing,
    even ones the shim hasn't implemented yet."""
    if name.startswith('_'):
        raise AttributeError(f"module 'matplotlib.pyplot' has no attribute {name!r}")
    if name not in _pyplot_missing_warned:
        _pyplot_missing_warned.add(name)
        try:
            print(f"[mpl-shim] plt.{name}() not implemented — returning None",
                  file=_sys.__stderr__)
        except Exception:
            pass
    def _missing(*args, **kwargs):
        return None
    return _missing
